def solve(challenge_id, phase):
    if not isinstance(challenge_id, int) or challenge_id <= 0:
        raise ValueError("Invalid challenge_id: must be a positive integer.")

    valid_phases = ['draft', 'active', 'completed', 'canceled']
    if phase not in valid_phases:
        raise ValueError(f"Invalid phase: must be one of {valid_phases}.")

    # Core logic to transition challenge phases
    if phase == 'draft':
        return "Challenge is in draft phase."
    elif phase == 'active':
        return "Challenge is now active."
    elif phase == 'completed':
        return "Challenge has been completed."
    elif phase == 'canceled':
        return "Challenge has been canceled."

    return None
